@charset "UTF-8";
body {
  margin: 0;
  font-family: "Inter", "Segoe UI", Arial, sans-serif;
}

/* ===== Header Bar ===== */
.header-bar {
  display: flex;
  align-items: center;
  background-color: #001f54;
  color: #fff;
  font-size: 13px;
  font-weight: 500;
  padding: 6px 10px;
  flex-wrap: wrap;
  border-radius: 4px 4px 0 0;
}

.header-item {
  padding: 4px 10px;
  border-right: 1px solid rgba(255, 255, 255, 0.2);
}

.header-item:last-child {
  border-right: none;
}

.header-item.title {
  font-weight: 600;
  display: inline-flex;
  align-items: center;
  gap: 4px;
  text-transform: capitalize;
  background: #082E69;
  justify-content: center;
}

.utility-title svg {
  stroke: #fff;
  vertical-align: middle;
  position: relative;
  top: -1px;
}

/* ===== General Info + Calculation Container Shared Style ===== */
.general-info,
.calc-container {
  background: #fff;
  border-radius: 6px;
  padding: 16px 20px;
  margin: 12px;
  box-shadow: 0 2px 6px rgba(0, 0, 0, 0.08);
  color: #0a0a0a;
}

.general-info h3,
.calc-container h3 {
  font-weight: 700;
  font-size: 16px;
  color: #002050;
  margin-bottom: 12px;
}

/* ===== Info Grid (2 columns) ===== */
.info-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px 20px;
}

.info-column {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

/* ===== Info Row ===== */
.info-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 6px 10px;
  font-size: 13px;
  border-bottom: 1px solid #f1f2f4;
  border-radius: 2px;
  background-color: #fff;
}

.info-row:nth-child(odd) {
  background-color: #F1F2F4;
}

.info-label {
  font-weight: 600;
  color: #222;
  flex: 1;
  white-space: nowrap;
}

.info-value {
  flex: 1;
  text-align: right;
  color: #111;
  font-weight: 500;
}

.unit {
  color: #666;
  font-size: 12px;
  margin-left: 3px;
}

/* ===== No Data ===== */
.no-data {
  text-align: center;
  color: #777;
  font-style: italic;
  padding: 12px;
}

/* ===== Usage Section ===== */
.usage-section {
  margin-top: 20px;
}

.usage-section h3 {
  font-weight: 700;
  font-size: 15px;
  color: #002050;
  margin-bottom: 10px;
}

.usage-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
}

.usage-table th {
  text-align: left;
  background-color: #f1f4f8;
  color: #002050;
  font-weight: 600;
  padding: 8px 10px;
}

.usage-table td {
  padding: 8px 10px;
  border-top: 1px solid #eee;
}

.usage-table tr:nth-child(odd) {
  background-color: #F1F2F4;
}

/* ===== Calculation Section ===== */
.calc-section {
  margin-top: 20px;
}

.calc-section h4 {
  font-size: 14px;
  font-weight: 600;
  color: #0a0a0a;
  margin-bottom: 16px;
}

/* ===== Collapsible Section Headers ===== */
.collapsible-header,
.calc-header {
  cursor: pointer;
  user-select: none;
}

.arrow {
  display: inline-block;
  font-size: 18px;
  transition: transform 0.3s ease;
  transform: rotate(-90deg); /* Default → right */
  margin-right: 6px;
}

.arrow.open {
  transform: rotate(0deg); /* Open ↓ down */
}

/* ===== Slide Animation ===== */
.slide-section {
  max-height: 0;
  opacity: 0;
  overflow: hidden;
  transform: translateY(-5px);
  transition: all 0.4s ease-in-out;
}

.slide-section.open {
  max-height: fit-content;
  opacity: 1;
  transform: translateY(0);
  padding-bottom: 10px;
}

.sub-container {
  background-color: #F8FAFC;
}

/* ===== Filter Bar with Selects ===== */
.filter-bar {
  background: #f8fafc;
  border: 1px solid #d9e2ec;
  border-radius: 6px;
  padding: 10px 16px;
  margin: 10px 12px 20px;
  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.05);
}

.filter-row {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
  align-items: center;
}

.filter-row select {
  flex: 1;
  min-width: 160px;
  padding: 10px;
  border: 1px solid #cbd5e1;
  border-radius: 4px;
  font-size: 13px;
  background: #fff;
  color: #0a0a0a;
  cursor: pointer;
}

.filter-row select:focus {
  border-color: #2563eb;
  box-shadow: 0 0 0 2px rgba(37, 99, 235, 0.15);
}

.filter-row button {
  background-color: #001f54;
  color: #fff;
  border: none;
  border-radius: 4px;
  padding: 6px 12px;
  cursor: pointer;
  font-size: 13px;
  font-weight: 600;
}

.filter-row button:hover {
  background-color: #003c8f;
}

/* === Top Toolbar === */
.top-toolbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 8px 0px 0px 10px;
}

.bill-count {
  font-size: 14px;
  color: #001f54;
}

.toolbar-right {
  display: flex;
  align-items: center;
  gap: 8px;
}

.icon-btn {
  background: transparent;
  border: none;
  padding: 6px 10px;
  display: flex;
  align-items: center;
  gap: 6px;
  cursor: pointer;
  color: #001f54;
  font-weight: 600;
  transition: background 0.2s ease;
}

.filters {
  background: #F1F2F4;
  border: 1px solid #F1F2F4;
  border-radius: 3px;
}

.filters svg {
  height: 24px;
}

.filters:hover {
  color: #1846b0;
}

.filter-label {
  font-size: 13px;
}

/* === Filter Bar Hide/Show Animation === */
.filter-bar-wrapper {
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.4s ease;
}

.filter-bar-wrapper.open {
  max-height: 200px;
  transition: max-height 0.4s ease;
}

/* ========== Filter Bar Container ========== */
.filter-bar-container {
  background: #F1F2F4;
  border-radius: 6px;
  box-shadow: 0 2px 6px rgba(0, 0, 0, 0.08);
  margin: 0px 0 20px;
  padding: 0 16px;
  overflow: hidden;
  max-height: 0;
  opacity: 0;
  transform: translateY(-8px);
  transition: all 0.4s ease-in-out;
}

.filter-bar-container.open {
  max-height: 500px;
  opacity: 1;
  transform: translateY(0);
  padding-top: 16px;
  padding-bottom: 16px;
}

/* ========== Grid Layout for Select Boxes ========== */
.filter-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 12px 20px;
}

.filter-item select {
  width: 100%;
  padding: 6px 8px;
  font-size: 13px;
  border-radius: 4px;
  border: 1px solid #ccc;
  background: #fff;
  color: #222;
}

/* ========== Responsive Grid ========== */
@media (max-width: 600px) {
  .filter-grid {
    grid-template-columns: repeat(2, 1fr);
  }
}
@media (max-width: 300px) {
  .filter-grid {
    grid-template-columns: 1fr;
  }
}
/* ========== Footer ========== */
.filter-footer {
  display: flex;
  justify-content: flex-end;
  margin-top: 16px;
}

.clear-btn {
  background: transparent;
  color: #1846b0;
  border: none;
  padding: 6px 12px;
  font-weight: 600;
  font-size: 13px;
  cursor: pointer;
  transition: background 0.3s;
  text-decoration: underline;
}

/* ===== Responsive ===== */
/* @media (max-width: 768px) {
  .info-grid {
    grid-template-columns: 1fr;
  }
}*/

