import React, { useState, useEffect, useMemo } from "https://esm.sh/react@18.2.0";
import ReactDOM from "https://esm.sh/react-dom@18.2.0";
import * as LucideIcons from "https://esm.sh/lucide-react@0.292.0";

// ------------------------- Info Row -------------------------
function InfoRow({ label, value }) {
  return (
    <div className="info-row">
      <span className="info-label">{label}</span>
      <span className="info-value">{value}</span>
    </div>
  );
}

// ------------------------- Usage Table -------------------------
function UsageTable({ usageData }) {
  if (!usageData?.length) return null;
  return (
    <div className="usage-section">
      <h3>Usage Charges</h3>
      <table className="usage-table">
        <tbody>
          {usageData.map((row, i) => (
            <tr key={i}>
              <td>{row.value || "-"}</td>
              <td>{row.usage || "-"}</td>
              <td>{row.uom || "-"}</td>
              <td>
                <b>${row.charge?.toFixed(2) || "0.00"}</b>
              </td>
              <td>{row.description || "-"}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

// ------------------------- Calculation Box -------------------------
function CalculationBox({ title, values }) {
  if (!values?.length) return null;

  const midIndex = Math.ceil(values.length / 2);
  const leftValues = values.slice(0, midIndex);
  const rightValues = values.slice(midIndex);

  return (
    <div className="calc-section">
      <h4>{title}</h4>
      <div className="info-grid">
        <div className="info-column">
          {leftValues.map((item, i) => (
            <InfoRow
              key={i}
              label={item.name || "-"}
              value={
                <>
                  {item.value || "-"} <span className="unit">{item.units || ""}</span>
                </>
              }
            />
          ))}
        </div>
        <div className="info-column">
          {rightValues.map((item, i) => (
            <InfoRow
              key={i}
              label={item.name || "-"}
              value={
                <>
                  {item.value || "-"} <span className="unit">{item.units || ""}</span>
                </>
              }
            />
          ))}
        </div>
      </div>
    </div>
  );
}

// ------------------------- Bill Record -------------------------
function BillRecord({ record, collapseAll }) {
  const [showHeader, setShowHeader] = useState(true);
  const [showCalc, setShowCalc] = useState(false);

  useEffect(() => {
    setShowHeader(!collapseAll);
  }, [collapseAll]);

  const usage = record.usage || [];
  const weatherValues = record.weathervalues || [];

  const dailyAverageValues = (record.regulardailyvalues || []).filter((v) =>
    v.name?.toLowerCase().includes("daily")
  );
  const regularValues = (record.regulardailyvalues || []).filter(
    (v) => !v.name?.toLowerCase().includes("daily")
  );

  const headerData = {
    title:
      record.utility_type?.charAt(0).toUpperCase() +
      record.utility_type?.slice(1).toLowerCase(),
    mid: record.meter_id || "-",
    said: record.service_account_id || "-",
    ratePlan: record.rate_plan || "-",
    locationDescription: record.location_description || "-",
    dateRange:
      record.billing_start_date && record.billing_end_date
        ? `${record.billing_start_date} - ${record.billing_end_date}`
        : "-",
    subtotal: `$${record.current_charges || "0.00"}`,
  };

  const infoLeft = [
    { label: "Bill SubTotal", value: `$${record.current_charges || "-"}` },
    { label: "Virtual Account Id", value: record.virtual_account_id || "-" },
    { label: "Service Account Id", value: record.service_account_id || "-" },
    { label: "Service Address", value: record.service_address || "-" },
    { label: "Service Zip", value: record.service_zip || "-" },
    { label: "Meter Id", value: record.meter_id || "-" },
    { label: "Delivery Location", value: record.delivery_location || "-" },
    { label: "Vendor Type", value: record.vendor_type || "-" },
    { label: "Location Address", value: record.location_address || "-" },
  ];

  const infoRight = [
    { label: "Location Description", value: record.location_description || "-" },
    { label: "Division", value: record.division || "-" },
    { label: "Service Start Date", value: record.billing_start_date || "-" },
    { label: "Service End Date", value: record.billing_end_date || "-" },
    {
      label: "Days Of Service",
      value:
        record.days_of_service && record.service_date_method
          ? `${record.days_of_service} (${record.service_date_method})`
          : "-",
    },
    {
      label: "Adjusted Service End Date",
      value: record.adjusted_service_end_date || "-",
    },
    { label: "Rate Plan", value: record.rate_plan || "-" },
    { label: "Estimated", value: record.estimated ? "YES" : "NO" },
    { label: "Prior Meter Reading", value: record.prior_meter_reading || "-" },
  ];

  const utilityIcons = {
    CABLE: "Tv",
    CARBONDIOXIDE: "Wind",
    CHILLEDWATER: "Snowflake",
    DIESEL: "Fuel",
    ELECTRIC: "Zap",
    FIREPROTECTION: "Shield",
    FUELCELL: "Battery",
    HOTWATER: "Flame",
    INTERNET: "Wifi",
    IRRIGATION: "Sprout",
    LIGHTING: "Lightbulb",
    NATURALGAS: "Flame",
    NG_COGEN: "Factory",
    NITROGEN: "FlaskConical",
    OIL2: "Fuel",
    OIL4: "Fuel",
    OIL6: "Fuel",
    OTHER: "Package",
    OXYGEN: "Activity",
    PESTCONTROL: "Bug",
    PROPANE: "Flame",
    REFUSE: "Trash2",
    SEWER: "Waves",
    SOLARPV: "Haze",
    STEAM: "CloudFog",
    STORMDRAIN: "CloudRain",
    STORMWATER: "CloudRainWind",
    TELEPHONE: "UtilityPole",
    UNLEADEDFUEL: "Fuel",
    UTILITYGAS: "Flame",
    WATER: "Droplet",
  };

  const iconName = utilityIcons[record.utility_type?.toUpperCase()] || "Factory";
  const Icon = LucideIcons[iconName];

  return (
    <div className="container">
      <div className="header-bar collapsible-header" onClick={() => setShowHeader(!showHeader)}>
        <span className={`arrow ${showHeader ? "open" : ""}`}>▾</span>
        <div className="header-item title utility-title">
          <span>{Icon && <Icon size={16} strokeWidth={2} />} {headerData.title}</span>
        </div>
        <div className="header-item">MID {headerData.mid}</div>
        <div className="header-item">SAID {headerData.said}</div>
        <div className="header-item">Rate Plan {headerData.ratePlan}</div>
        <div className="header-item">{headerData.locationDescription}</div>
        <div className="header-item">{headerData.dateRange}</div>
        <div className="header-item">{headerData.subtotal}</div>
      </div>

      <div className={`sub-container slide-section ${showHeader ? "open" : ""}`}>
        <div className="general-info">
          <h3>General Information</h3>
          <div className="info-grid">
            <div className="info-column">{infoLeft.map((item) => <InfoRow key={item.label} {...item} />)}</div>
            <div className="info-column">{infoRight.map((item) => <InfoRow key={item.label} {...item} />)}</div>
          </div>
          <UsageTable usageData={usage} />
        </div>

        <div className="calc-container">
          <h3 className="calc-header" onClick={() => setShowCalc(!showCalc)}>
            <span className={`arrow ${showCalc ? "open" : ""}`}>▾</span> Calculated Values
          </h3>
          <div className={`slide-section ${showCalc ? "open" : ""}`}>
            <CalculationBox title="Regular Values" values={regularValues} />
            <CalculationBox title="Weather Values" values={weatherValues} />
            <CalculationBox title="Daily-average Values" values={dailyAverageValues} />
          </div>
        </div>
      </div>
    </div>
  );
}

// ------------------------- Main App -------------------------
function App() {
  const [data, setData] = useState(appsmith.model?.data || []);
  const [filters, setFilters] = useState({
    utility_type: "",
    meter_id: "",
    service_account_id: "",
    service_address: "",
    location_description: "",
  });
  const [filteredData, setFilteredData] = useState([]);
  const [collapseAll, setCollapseAll] = useState(false);
  const [showFilters, setShowFilters] = useState(false);

  // Unique dropdown options
  const options = useMemo(() => {
    const unique = (key) => [...new Set(data.map((r) => r[key]).filter(Boolean))];
    return {
      utility_type: unique("utility_type"),
      meter_id: unique("meter_id"),
      service_account_id: unique("service_account_id"),
      service_address: unique("service_address"),
      location_description: unique("location_description"),
    };
  }, [data]);

  useEffect(() => {
    const interval = setInterval(() => {
      const newData = appsmith.model?.data || [];
      if (newData.length && newData.length !== data.length) setData([...newData]);
    }, 500);
    return () => clearInterval(interval);
  }, [data]);

  useEffect(() => {
    let filtered = [...data];
    Object.entries(filters).forEach(([key, val]) => {
      if (val) filtered = filtered.filter((r) => r[key] === val);
    });
    setFilteredData(filtered);
  }, [filters, data]);

  const handleFilterChange = (key, value) => setFilters((prev) => ({ ...prev, [key]: value }));

  const clearFilters = () =>
    setFilters({
      utility_type: "",
      meter_id: "",
      service_account_id: "",
      service_address: "",
      location_description: "",
    });

  const FilterBar = () => (
  <div className={`filter-bar-container ${showFilters ? "open" : ""}`}>
    <div className="filter-grid">
      {Object.keys(filters).map((key) => (
        <div key={key} className="filter-item">
          <select
            value={filters[key]}
            onChange={(e) => handleFilterChange(key, e.target.value)}
          >
            <option value="">
              {key.replace(/_/g, " ").replace(/\b\w/g, (c) => c.toUpperCase())}
            </option>
            {options[key].map((opt) => (
              <option key={opt} value={opt}>
                {opt}
              </option>
            ))}
          </select>
        </div>
      ))}
    </div>

    <div className="filter-footer">
      <button className="clear-btn" onClick={clearFilters}>
        Clear
      </button>
    </div>
  </div>
);


	const CollapseAllIcon = LucideIcons['FoldVertical']

  const ExpandAllIcon = LucideIcons['UnfoldVertical']

  return (
    <div>
      {/* === Top Control Bar === */}
      <div className="top-toolbar">
        <div className="toolbar-left">
          <span className="bill-count">Bill Blocks total: <b>{filteredData.length}</b></span>
        </div>
						<div className="toolbar-right">
							<button
								className="icon-btn"
								title={collapseAll ? "Expand All" : "Collapse All"}
								onClick={() => setCollapseAll(!collapseAll)}
							>
								{collapseAll ? <ExpandAllIcon /> : <CollapseAllIcon />}
							</button>
							<button
								className="icon-btn filters"
								title="Toggle Filters"
								onClick={() => setShowFilters(!showFilters)}
							>
								<LucideIcons.Filter size={16} />
								<span className="filter-label">Filters</span>
							</button>
						</div>
      </div>

      <FilterBar />

      {filteredData.map((record, i) => (
        <BillRecord key={i} record={record} collapseAll={collapseAll} />
      ))}
    </div>
  );
}

ReactDOM.render(<App />, document.getElementById("root"));
